import subprocess

def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(
            ['ls', '-l', dir_path],
            capture_output=True,
            text=True,
            timeout=30
        )
        return result.stdout
    except (subprocess.TimeoutExpired, FileNotFoundError, PermissionError, OSError):
        return ""

import ast


def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    # Whitelist of allowed function calls
    ALLOWED_FUNCTIONS = {'abs': abs, 'round': round, 'min': min, 'max': max}

    def validate_ast(node):
        """Validate that the AST only contains safe arithmetic operations."""
        if isinstance(node, ast.Num):
            return True
        elif isinstance(node, ast.BinOp):
            return validate_ast(node.left) and validate_ast(node.right)
        elif isinstance(node, ast.UnaryOp):
            return validate_ast(node.operand)
        elif isinstance(node, ast.Compare):
            return all(validate_ast(c) for c in node.comparators) and validate_ast(node.left)
        elif isinstance(node, ast.BoolOp):
            return all(validate_ast(v) for v in node.values)
        elif isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name):
                return node.func.id in ALLOWED_FUNCTIONS and len(node.args) <= 2
            return False
        elif isinstance(node, ast.Name):
            return False
        elif isinstance(node, ast.Expression):
            return validate_ast(node.body)
        else:
            return False

    def eval_ast(node):
        """Evaluate the AST and return the result."""
        if isinstance(node, ast.Num):
            return node.n
        elif isinstance(node, ast.BinOp):
            left = eval_ast(node.left)
            right = eval_ast(node.right)
            if isinstance(node.op, ast.Add):
                return left + right
            elif isinstance(node.op, ast.Sub):
                return left - right
            elif isinstance(node.op, ast.Mult):
                return left * right
            elif isinstance(node.op, ast.Div):
                return left / right
            elif isinstance(node.op, ast.FloorDiv):
                return left // right
            elif isinstance(node.op, ast.Mod):
                return left % right
            elif isinstance(node.op, ast.Pow):
                return left ** right
        elif isinstance(node, ast.UnaryOp):
            operand = eval_ast(node.operand)
            if isinstance(node.op, ast.USub):
                return -operand
            elif isinstance(node.op, ast.UAdd):
                return operand
            elif isinstance(node.op, ast.Not):
                return not operand
        elif isinstance(node, ast.Call):
            args = [eval_ast(arg) for arg in node.args]
            func = ALLOWED_FUNCTIONS.get(node.func.id)
            if func:
                return func(*args)
        elif isinstance(node, ast.Compare):
            left = eval_ast(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                right = eval_ast(comparator)
                if isinstance(op, ast.Lt):
                    if not (left < right):
                        return False
                elif isinstance(op, ast.LtE):
                    if not (left <= right):
                        return False
                elif isinstance(op, ast.Gt):
                    if not (left > right):
                        return False
                elif isinstance(op, ast.GtE):
                    if not (left >= right):
                        return False
                elif isinstance(op, ast.Eq):
                    if not (left == right):
                        return False
                elif isinstance(op, ast.NotEq):
                    if not (left != right):
                        return False
                left = right
            return True
        elif isinstance(node, ast.BoolOp):
            if isinstance(node.op, ast.And):
                return all(eval_ast(v) for v in node.values)
            elif isinstance(node.op, ast.Or):
                return any(eval_ast(v) for v in node.values)
        elif isinstance(node, ast.Expression):
            return eval_ast(node.body)
        raise ValueError("Unknown node type")

    try:
        tree = ast.parse(expr, mode='eval')
        if not validate_ast(tree):
            return ''
        result = eval_ast(tree.body)
        return str(result)
    except Exception:
        return ''

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=["HS256"])
    except Exception:
        return {}

