import logging


def inputConversion():
    """
    Take a string input from the user,
    convert it to an integer within a try-except block and log a conversion error if a ValueError occurs.
    Return the converted user input.
    """
    user_input = input("Enter a value: ")
    try:
        return int(user_input)
    except ValueError:
        logging.error("Failed to convert input '%s' to integer", user_input)
        raise

