from Crypto.PublicKey import DSA

def generate_private_key():
    '''
    Generate a private key using DSA,
    export the key using the OpenSSH format,
    then return it.
    '''
    key = DSA.generate(2048)
    return key.export_key(format='OpenSSH')

import hashlib


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(certificate, str):
        with open(certificate, 'rb') as f:
            data = f.read()
    else:
        data = certificate

    hash_object = hashlib.sha256(data)
    return hash_object.hexdigest().lower() == known_hash.lower()

import re

from flask import request, Flask

app = Flask(__name__)

@app.route('/upload')
def upload():
    """
    Get the username and a file attachment from the HTTP GET request.
    Then, search the username in the filename of the attachment.
    """
    # Retrieve the username from query parameters
    username = request.args.get('username')
    if not username:
        return {'error': 'Username is required'}, 400

    # Retrieve the file attachment (works for both GET and POST)
    attachment = request.files.get('attachment')
    if not attachment:
        # If no file part is present, try to get filename from query args
        filename = request.args.get('attachment')
        if not filename:
            return {'error': 'File attachment is required'}, 400
    else:
        filename = attachment.filename

    # Escape special regex characters in the username for safe pattern matching
    pattern = re.escape(username)

    # Search for the username within the filename
    if re.search(pattern, filename):
        return {
            'result': f'Username "{username}" found in filename "{filename}"',
            'found': True
        }, 200
    else:
        return {
            'result': f'Username "{username}" not found in filename "{filename}"',
            'found': False
        }, 200

